définis/definis.syntax:
définis/definis [le/la/les/l contenu de] {target} depuis {source}
set [le/la/les/l] titre à/a {title}
set [le/la/les/l] contenu de {element} à/a {value}
set [le/la/les/l] id de {element} à/a {id} [comme {selected}]
set [le/la/les/l] texte de {button}/{input}/{span}/{label} à/a {text}
set [le/la/les/l] taille de {input} à/a {size}
set attribut {name} de {element} à/a {value}
set style {name} de {element}/corps à/a {style}
set [le/la/les/l] styles de {element} à/a {styles}
set [le/la/les/l] défaut/defaut de {select} à/a {value}
set {select} depuis List [comme {value}]
